lexer grammar SYsULexer;

@lexer::members {
    std::string currentFilename = "<unknown>";
    int currentLine = 1;
    int currentCol = 1;
    bool atStartOfLine = true;
    bool hadLeadingSpace = false;

    virtual std::unique_ptr<antlr4::Token> emit() override {
        auto token = Lexer::emit();

        if (token->getType() == EOF) {
            // Format EOF token as required
            std::ostringstream oss;
            oss << "eof '' Loc=<" << currentFilename << ":" << currentLine << ":" << (currentCol + 1) << ">";
            token->setText(oss.str());
            return token;
        }

        // Get token name and value
        std::string tokenName = _vocabulary.getSymbolicName(token->getType());
        if (tokenName.empty()) {
            tokenName = std::to_string(token->getType());
        }
        std::string tokenValue = token->getText();

        // Format token with location info
        std::ostringstream oss;
        oss << tokenName << " '" << tokenValue << "'";
        if (atStartOfLine) oss << " [StartOfLine]";
        if (hadLeadingSpace) oss << " [LeadingSpace]";
        oss << " Loc=<" << currentFilename << ":" << currentLine << ":" << currentCol << ">";

        token->setText(oss.str());

        // Update position tracking
        currentCol += tokenValue.size();
        atStartOfLine = false;
        hadLeadingSpace = false;

        return token;
    }
}

